// // This module selects between two 16-bit inputs, I0 and I1, based on the value of the selection signal S. If S is 1, the output out will be equal to I0; if S is 0, the output will be equal to I1.
module top_module( I0,I1,S,out);parameter bit_size = 16;

	input  [bit_size-1:0] I0;
	input  [bit_size-1:0] I1;
	input  S;

	output [bit_size-1:0] out;



	assign out=S ? I1: I0;




endmodule
